import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Token 統計: コスト監視とデータ分析 | Antigravity Manager","description":"Token Stats 統計機能の使用方法を学びます。レスポンスから token データを抽出する方法、モデルとアカウント別に使用量を分析する方法、Top リストで最も高いモデルとアカウントを特定する方法、統計欠損問題をトラブルシューティングする方法を理解します。","frontmatter":{"title":"Token 統計: コスト監視とデータ分析 | Antigravity Manager","sidebarTitle":"一番高いのは誰か一目でわかる","subtitle":"Token 統計: コスト監視とデータ分析","description":"Token Stats 統計機能の使用方法を学びます。レスポンスから token データを抽出する方法、モデルとアカウント別に使用量を分析する方法、Top リストで最も高いモデルとアカウントを特定する方法、統計欠損問題をトラブルシューティングする方法を理解します。","tags":["Token Stats","コスト","監視","SQLite","使用量統計"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),d={name:"ja/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function l(s,t,n,i,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="token-stats-コスト視点の統計口径とグラフ解釈" tabindex="-1">Token Stats：コスト視点の統計口径とグラフ解釈 <a class="header-anchor" href="#token-stats-コスト視点の統計口径とグラフ解釈" aria-label="Permalink to &quot;Token Stats：コスト視点の統計口径とグラフ解釈&quot;">​</a></h1><p>クライアントを Antigravity Tools に接続しましたが、「誰がお金を使っているか、どこが高いか、あるモデルが急に跳ね上がったのか」は直感で判断するのが難しいことがよくあります。このレッスンでは 1 つのことだけをします：Token Stats ページのデータ口径を明確にし、グラフでコスト問題を素早く特定する方法を教えます。</p><h2 id="学んだ後できること" tabindex="-1">学んだ後できること <a class="header-anchor" href="#学んだ後できること" aria-label="Permalink to &quot;学んだ後できること&quot;">​</a></h2><ul><li>Token Stats のデータがどこから来るかを明確に説明できる（いつ記録されるか、どのような場合に欠損するか）</li><li>時間/日/週で観察ウィンドウを切り替え、「1 日だけ見る」で誤判断を回避する</li><li>「モデル別/アカウント別」2 種類のビューで、トレンドグラフで異常なピークを見つける</li><li>Top リストで最も高いモデル/アカウントをロックし、リクエストログに戻って根本原因を追跡する</li></ul><h2 id="現在の悩み" tabindex="-1">現在の悩み <a class="header-anchor" href="#現在の悩み" aria-label="Permalink to &quot;現在の悩み&quot;">​</a></h2><ul><li>呼び出しが高くなったと感じるが、モデルが変わったのか、アカウントが変わったのか、ある日突然量が増えたのかがわからない</li><li><code>X-Mapped-Model</code> を見たが、統計がどのモデル口径で計算されているかが不明</li><li>Token Stats に時々 0 または「データなし」が表示され、トラフィックがないのか統計されていないのかがわからない</li></ul><h2 id="この方法をいつ使うか" tabindex="-1">この方法をいつ使うか <a class="header-anchor" href="#この方法をいつ使うか" aria-label="Permalink to &quot;この方法をいつ使うか&quot;">​</a></h2><ul><li>コスト最適化を行う場合：まず「誰が高いか」を量化する</li><li>突然のレート制限/異常をトラブルシューティングする場合：ピーク時間点を使ってリクエストログと照合する</li><li>モデルルーティング/クォータガバナンス設定変更後、コストが期待通り低下したかを検証する場合</li></ul><h2 id="token-stats-とは" tabindex="-1">Token Stats とは？ <a class="header-anchor" href="#token-stats-とは" aria-label="Permalink to &quot;Token Stats とは？&quot;">​</a></h2><p><strong>Token Stats</strong>は Antigravity Tools のローカル使用量統計ページです：プロキシはリクエストを転送した後、レスポンス JSON またはストリーミングデータから <code>usage/usageMetadata</code> の token 数を抽出しようとし、各リクエストをアカウントとモデル別にローカル SQLite（<code>token_stats.db</code>）に書き込み、最後に UI で時間/モデル/アカウント別に集約して表示します。</p><div class="info custom-block"><p class="custom-block-title">よく踏む点を先に説明</p><p>Token Stats の「モデル」口径はリクエスト内の <code>model</code> フィールド（または Gemini の <code>/v1beta/models/&lt;model&gt;</code> パス解析）から来るもので、ルーティング後の <code>X-Mapped-Model</code> と同じではありません。</p></div><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><ul><li>すでに 1 回プロキシ呼び出しを実行していること（<code>/healthz</code> ヘルスチェックだけに留まっていない）</li><li>上流レスポンスが解析可能な token 使用量フィールドを返すこと（そうでない場合、統計が欠損します）</li></ul><div class="tip custom-block"><p class="custom-block-title">推奨読み合わせ</p><p>モデルマッピングを使って <code>model</code> を別の物理モデルにルーティングしている場合、先に <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/advanced/model-router/">モデルルーティング：カスタムマッピング、ワイルドカード優先順位とプリセット戦略</a></strong> を参照し、「統計口径」に戻るとより直感的になります。</p></div><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>Token Stats のデータチェーンは 3 つの部分に分割できます：</p><ol><li>プロキシミドルウェアがレスポンスから token 使用量を抽出しようとする（<code>usage</code>/<code>usageMetadata</code> に互換、ストリーミングも解析）</li><li>同時に <code>account_email + input_tokens + output_tokens</code> を取得した場合、ローカル SQLite（<code>token_stats.db</code>）に書き込む</li><li>UI が Tauri <code>invoke(get_token_stats_*)</code> を通じて集約データを取得し、時間/日/週で表示</li></ol><h2 id="さあやってみよう" tabindex="-1">さあやってみよう <a class="header-anchor" href="#さあやってみよう" aria-label="Permalink to &quot;さあやってみよう&quot;">​</a></h2><h3 id="ステップ-1-まず「トラフィックがある」ことを確認する" tabindex="-1">ステップ 1：まず「トラフィックがある」ことを確認する <a class="header-anchor" href="#ステップ-1-まず「トラフィックがある」ことを確認する" aria-label="Permalink to &quot;ステップ 1：まず「トラフィックがある」ことを確認する&quot;">​</a></h3><p><strong>理由</strong> Token Stats 統計は実際のリクエストから来ます。プロキシを起動しただけではモデルリクエストを 1 回も送っていない場合、ページに「データなし」が表示されます。</p><p>方法：<strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">ローカルリバースプロキシを起動して最初のクライアントを接続</a></strong> ですでに検証成功した呼び出し方法を再利用し、1-2 回リクエストを送ってください。</p><p><strong>確認すべきもの</strong>：Token Stats ページが「読み込み中/データなし」からグラフまたはリストに変わること。</p><h3 id="ステップ-2-適切な時間ウィンドウを選択する-時間-日-週" tabindex="-1">ステップ 2：適切な時間ウィンドウを選択する（時間/日/週） <a class="header-anchor" href="#ステップ-2-適切な時間ウィンドウを選択する-時間-日-週" aria-label="Permalink to &quot;ステップ 2：適切な時間ウィンドウを選択する（時間/日/週）&quot;">​</a></h3><p><strong>理由</strong> 同じデータでも、異なるウィンドウで見る「ピーク/トレンド」は完全に異なります。UI で 3 種類のウィンドウに対応する取得範囲も異なります：</p><ul><li>時間：直近 24 時間</li><li>日：直近 7 日</li><li>週：直近 4 週間（トレンドビューは直近 30 日で集約）</li></ul><p><strong>確認すべきもの</strong>：切り替え後、トレンドグラフの横軸粒度が変わる（時間は「時」まで表示、日は「月/日」まで表示、週は「年-W週号」まで表示）。</p><h3 id="ステップ-3-まずトップ総覧を見て、「コスト規模」を確定する" tabindex="-1">ステップ 3：まずトップ総覧を見て、「コスト規模」を確定する <a class="header-anchor" href="#ステップ-3-まずトップ総覧を見て、「コスト規模」を確定する" aria-label="Permalink to &quot;ステップ 3：まずトップ総覧を見て、「コスト規模」を確定する&quot;">​</a></h3><p><strong>理由</strong> 総覧カードは最初に 3 つの質問に答えられます：総量が大きいかどうか、入力/出力の比率が異常か、参加するアカウント/モデルが突然増えたかどうか。</p><p>これらの項目に重点を置いてください：</p><ul><li>総 Token（<code>total_tokens</code>）</li><li>入力/出力 Token（<code>total_input_tokens</code> / <code>total_output_tokens</code>）</li><li>アクティブアカウント数（<code>unique_accounts</code>）</li><li>使用モデル数（UI は直接「モデル別統計リスト」の長さを使用）</li></ul><p><strong>確認すべきもの</strong>：「アクティブアカウント数」が突然跳ね上がると、通常、短時間でより多くのアカウントを実行していることを意味します（例：ローテーション戦略に切り替える）。</p><h3 id="ステップ-4-「モデル別-アカウント別使用トレンド」で異常なピークを捕捉する" tabindex="-1">ステップ 4：「モデル別/アカウント別使用トレンド」で異常なピークを捕捉する <a class="header-anchor" href="#ステップ-4-「モデル別-アカウント別使用トレンド」で異常なピークを捕捉する" aria-label="Permalink to &quot;ステップ 4：「モデル別/アカウント別使用トレンド」で異常なピークを捕捉する&quot;">​</a></h3><p><strong>理由</strong> トレンドグラフは「突然高くなった」を捕捉するのに最も適した入り口です。原因を先に知る必要はなく、「どの日/どの時間が跳ね上がったか」を先に丸で囲みます。</p><p>方法：</p><ol><li>トレンドグラフの右上隅で「モデル別 / アカウント別」を切り替える</li><li>マウスをホバー（Tooltip）して Top 値を見る、「突然 1 位になったもの」を優先的に注目する</li></ol><p><strong>確認すべきもの</strong>：</p><ul><li>モデル別：あるモデルが特定の時間帯で突然上昇</li><li>アカウント別：あるアカウントが特定の時間帯で突然上昇</li></ul><h3 id="ステップ-5-top-リストで「最も高いターゲット」をロックする" tabindex="-1">ステップ 5：Top リストで「最も高いターゲット」をロックする <a class="header-anchor" href="#ステップ-5-top-リストで「最も高いターゲット」をロックする" aria-label="Permalink to &quot;ステップ 5：Top リストで「最も高いターゲット」をロックする&quot;">​</a></h3><p><strong>理由</strong> トレンドグラフは「いつ異常か」を教えてくれ、Top リストは「誰が高いか」を教えてくれます。これらを交差させると、トラブルシューティング範囲を素早く特定できます。</p><p>方法：</p><ul><li>「モデル別」ビューで、「モデル別詳細統計」テーブルの <code>total_tokens / request_count / 比率</code> を見る</li><li>「アカウント別」ビューで、「アカウント詳細統計」テーブルの <code>total_tokens / request_count</code> を見る</li></ul><p><strong>確認すべきもの</strong>：最も高いモデル/アカウントが先頭に並び、<code>request_count</code> が「1 回特に高い」か「回数が特に多い」かを区別できる。</p><h3 id="ステップ-6-オプション-token-stats-db-を見つけ、バックアップ-照合を行う" tabindex="-1">ステップ 6（オプション）：<code>token_stats.db</code> を見つけ、バックアップ/照合を行う <a class="header-anchor" href="#ステップ-6-オプション-token-stats-db-を見つけ、バックアップ-照合を行う" aria-label="Permalink to &quot;ステップ 6（オプション）：`token_stats.db` を見つけ、バックアップ/照合を行う&quot;">​</a></h3><p><strong>理由</strong> 「統計欠損」を疑う場合、またはオフライン分析を行いたい場合、SQLite ファイルを直接取得するのが最も信頼できます。</p><p>方法：Settings の Advanced 領域で「Open Data Directory」をクリックし、データディレクトリで <code>token_stats.db</code> を見つけます。</p><p><strong>確認すべきもの</strong>：ファイルリストに <code>token_stats.db</code> があること（ファイル名はバックエンドで固定されています）。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>Token Stats 統計が「レスポンス内の usage/usageMetadata から抽出してローカル SQLite に落とし込む」であることを明確に説明できる、クラウド課金ではない</li><li>「モデル別/アカウント別」2 種類のトレンドビューで、具体的なピーク時間帯を指摘できる</li><li>Top リストで実行可能なトラブルシューティング結論を出せる：まずどのモデルまたはアカウントを確認するか</li></ul><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>現象</th><th>よくある原因</th><th>対処法</th></tr></thead><tbody><tr><td>Token Stats に「データなし」が表示される</td><td>モデルリクエストを実際に生成していない；または上流レスポンスが解析可能な token フィールドを持っていない</td><td>まず検証済みの利用可能なクライアントでリクエストを送る；その後、レスポンスに <code>usage/usageMetadata</code> が含まれているかを確認</td></tr><tr><td>統計が「モデル」で見て間違っている</td><td>統計口径はリクエスト内の <code>model</code> を使用し、<code>X-Mapped-Model</code> ではない</td><td>モデルルーティングを「リクエストモデル -&gt; マッピングモデル」と見る；統計は「リクエストモデル」を見る</td></tr><tr><td>アカウント次元が欠損している</td><td><code>X-Account-Email</code> を取得し、token 使用量を解析した場合のみ書き込まれる</td><td>リクエストが実際にアカウントプールに到達したことを確認；その後、リクエストログ/レスポンスヘッダーと照合</td></tr><tr><td>Proxy Monitor を有効にすると統計データが大きくなる</td><td>Proxy Monitor が有効な場合、各リクエストの token が 2 回記録される</td><td>これは既知の実装詳細であり、相対トレンド分析には影響しない；正確な値が必要な場合、Monitor を一時的に無効にして再測定</td></tr></tbody></table><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Token Stats のコア価値は「コスト問題を量化する」こと、まず特定し、次に最適化する</li><li>統計書き込み時、アカウントと token 使用量は必須；モデルが欠損している場合、<code>&quot;unknown&quot;</code> として記録される（書き込みを阻止しない）</li><li>より精密なコスト制御を行いたい場合、次は通常モデルルーティングまたはクォータガバナンスに戻る</li></ul><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>次のレッスンでは長いセッションの「隠れた安定性問題」を解決します：<strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/advanced/context-compression/">長いセッションの安定性：コンテキスト圧縮、署名キャッシュとツール結果圧縮</a></strong>。</p></blockquote><p>学べること：</p><ul><li>3 層の漸進的コンテキスト圧縮がそれぞれ何をするか</li><li>なぜ「署名キャッシュ」が 400 署名エラーを減らせるのか</li><li>ツール結果圧縮は何を削除し、何を残すのか</li></ul><hr><h2 id="付録-ソースコード参考" tabindex="-1">付録：ソースコード参考 <a class="header-anchor" href="#付録-ソースコード参考" aria-label="Permalink to &quot;付録：ソースコード参考&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Token Stats UI：時間ウィンドウ/ビュー切り替えとデータ取得</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>Token Stats UI：空データヒント（「データなし」）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Token 使用量抽出：リクエストから model 解析、レスポンスから usage/usageMetadata 解析</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Token 使用量抽出：ストリーミングと JSON レスポンス usage フィールド解析</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Token Stats 書き込み点：アカウント+token 取得後 SQLite に書き込み</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>データベースファイル名とテーブル構造：<code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>書き込みロジック：<code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>クエリロジック：時間/日/週、アカウント別/モデル別、トレンドと総覧</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Tauri コマンド：<code>get_token_stats_*</code> をフロントエンドに公開</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>アプリ起動時に Token Stats DB を初期化</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>設定ページ：データディレクトリの取得/オープン（<code>token_stats.db</code> を見つけるため）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const g=e(d,[["render",l]]);export{b as __pageData,g as default};
